Component({
  properties: {
    type: {
      type: Number,
      value: 1
    },
    list: {
      type: Array,
      value: []
    }
  },
  methods: {
    clickItem(e) {
      const item = e.currentTarget.dataset.item
      this.triggerEvent('clickItem', {
        data: {
          type: 'article',
          id: item.id
        }
      })
    }
  },
})
